class Solution {
public:
    string originalDigits(string s) {
        int count[26] = {0};
        for (char c : s) {
            count[c - 'a']++;
        }

        int digits[10] = {0};
        digits[0] = count['z'];
        digits[2] = count['w'];
        digits[4] = count['u'];
        digits[6] = count['x'];
        digits[8] = count['g'];

        digits[3] = count['h'] - digits[8];
        digits[5] = count['f'] - digits[4];
        digits[7] = count['s'] - digits[6];

        digits[1] = count['o'] - digits[0] - digits[2] - digits[4];
        digits[9] = count['i'] - digits[5] - digits[6] - digits[8];

        string result;
        for (int i = 0; i < 10; i++) {
            while (digits[i]--) {
                result += '0' + i;
            }
        }

        return result;
    }
};
```
